def test_magento_transform_with_empty_data():
    transformer = MagentoTransformer()
    data = {}
    # Implementation returns [] for empty input
    assert transformer.transform(data) == []

def test_magento_transform_with_missing_fields():
    """Data has index but no attributes; implementation raises TypeError on 'k in attributes'."""
    transformer = MagentoTransformer()
    data = {
        "[data-role=swatch-options]": {
            "Magento_Swatches/js/swatch-renderer": {
                "jsonConfig": {
                    "sku": "sku1",
                    "optionPrices": "price1",
                    "images": "image1",
                    "index": {"pid1": {"k1": "v1"}},
                }
            }
        }
    }
    with pytest.raises(TypeError, match="NoneType"):
        transformer.transform(data)
